targetCode.css:
/* cssBasico.css - version <= 450 */
em {
  width: 100px;
  height: 100px;
}

#p1 {
  display: inline-block;
  background: blue;
}

#p2 {
  display: block;
  background: red;
  float: left;
}

targetCode.javascript:
/* cssPos.css - version > 450 */
@media (min-width: 451px) {
  em {
    display: block;
    width: 100px;
    height: 100px;
  }

  #p1 {
    background: blue;
    float: right;
  }

  #p2 {
    background: red;
    float: right;
    clear: right;
  }
}
